import { create } from 'zustand';

const useSettingsStore = create((set, get) => ({
  dailyBudgetHours: 8,
  lunchDurationMinutes: 60,
  idleThresholdMinutes: 5,
  autoPauseOnIdle: true,
  autoLaunch: false,
  reminderMinutesBefore: 5,
  showWidgetReminders: true,

  loadSettings: async () => {
    try {
      const settings = await window.electronAPI.dbAll(
        'SELECT key, value FROM settings',
        []
      );

      const settingsObj = {};
      settings.forEach(({ key, value }) => {
        if (key === 'dailyBudgetHours') {
          settingsObj.dailyBudgetHours = parseFloat(value);
        } else if (key === 'lunchDurationMinutes') {
          settingsObj.lunchDurationMinutes = parseInt(value);
        } else if (key === 'idleThresholdMinutes') {
          settingsObj.idleThresholdMinutes = parseInt(value);
        } else if (key === 'autoPauseOnIdle') {
          settingsObj.autoPauseOnIdle = value === 'true';
        } else if (key === 'autoLaunch') {
          settingsObj.autoLaunch = value === 'true';
        } else if (key === 'reminderMinutesBefore') {
          settingsObj.reminderMinutesBefore = parseInt(value);
        } else if (key === 'showWidgetReminders') {
          settingsObj.showWidgetReminders = value === 'true';
        }
      });

      set(settingsObj);
    } catch (error) {
      console.error('Error loading settings:', error);
    }
  },

  updateSetting: async (key, value) => {
    try {
      await window.electronAPI.dbRun(
        'INSERT OR REPLACE INTO settings (key, value) VALUES (?, ?)',
        [key, String(value)]
      );

      set({ [key]: value });

      // Handle special settings
      if (key === 'autoLaunch') {
        await window.electronAPI.setAutoLaunch(value);
      }
    } catch (error) {
      console.error('Error updating setting:', error);
      throw error;
    }
  },
}));

export default useSettingsStore;

