import React, { useState, useEffect } from 'react';
import { Save } from 'lucide-react';
import useSettingsStore from '../stores/settingsStore';

function Settings() {
  const settingsStore = useSettingsStore();
  const [dailyBudget, setDailyBudget] = useState(settingsStore.dailyBudgetHours);
  const [lunchDuration, setLunchDuration] = useState(settingsStore.lunchDurationMinutes);
  const [idleThreshold, setIdleThreshold] = useState(settingsStore.idleThresholdMinutes);
  const [autoPause, setAutoPause] = useState(settingsStore.autoPauseOnIdle);
  const [autoLaunch, setAutoLaunch] = useState(settingsStore.autoLaunch);
  const [reminderMinutes, setReminderMinutes] = useState(settingsStore.reminderMinutesBefore);
  const [showWidgetReminders, setShowWidgetReminders] = useState(settingsStore.showWidgetReminders);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    setDailyBudget(settingsStore.dailyBudgetHours);
    setLunchDuration(settingsStore.lunchDurationMinutes);
    setIdleThreshold(settingsStore.idleThresholdMinutes);
    setAutoPause(settingsStore.autoPauseOnIdle);
    setAutoLaunch(settingsStore.autoLaunch);
    setReminderMinutes(settingsStore.reminderMinutesBefore);
    setShowWidgetReminders(settingsStore.showWidgetReminders);
  }, [settingsStore]);

  const handleSave = async () => {
    try {
      await settingsStore.updateSetting('dailyBudgetHours', dailyBudget);
      await settingsStore.updateSetting('lunchDurationMinutes', lunchDuration);
      await settingsStore.updateSetting('idleThresholdMinutes', idleThreshold);
      await settingsStore.updateSetting('autoPauseOnIdle', autoPause);
      await settingsStore.updateSetting('autoLaunch', autoLaunch);
      await settingsStore.updateSetting('reminderMinutesBefore', reminderMinutes);
      await settingsStore.updateSetting('showWidgetReminders', showWidgetReminders);
      setSaved(true);
      setTimeout(() => setSaved(false), 2000);
    } catch (error) { alert('Failed to save: ' + error.message); }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-3">
      <div className="bg-white rounded-lg shadow-sm">
        <div className="p-3 border-b border-gray-100">
          <h2 className="text-sm font-semibold text-gray-900">Settings</h2>
        </div>
        <div className="p-3 space-y-3">
          <div className="grid grid-cols-3 gap-3">
            <div>
              <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Daily Budget (hrs)</label>
              <input type="number" min="1" max="24" step="0.5" value={dailyBudget} onChange={(e) => setDailyBudget(parseFloat(e.target.value))}
                className="w-full px-2 py-1 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent" />
            </div>
            <div>
              <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Lunch (min)</label>
              <input type="number" min="15" max="120" step="15" value={lunchDuration} onChange={(e) => setLunchDuration(parseInt(e.target.value))}
                className="w-full px-2 py-1 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent" />
            </div>
            <div>
              <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Idle Threshold (min)</label>
              <input type="number" min="1" max="60" step="1" value={idleThreshold} onChange={(e) => setIdleThreshold(parseInt(e.target.value))}
                className="w-full px-2 py-1 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent" />
            </div>
          </div>

          <div className="flex items-center justify-between py-1">
            <span className="text-xs text-gray-700">Auto-pause on idle</span>
            <button onClick={() => setAutoPause(!autoPause)}
              className={`relative inline-flex h-5 w-9 items-center rounded-full transition-colors ${autoPause ? 'bg-primary-500' : 'bg-gray-200'}`}>
              <span className={`inline-block h-3.5 w-3.5 transform rounded-full bg-white transition-transform ${autoPause ? 'translate-x-4.5' : 'translate-x-0.5'}`} />
            </button>
          </div>

          <div className="flex items-center justify-between py-1">
            <span className="text-xs text-gray-700">Launch on startup</span>
            <button onClick={() => setAutoLaunch(!autoLaunch)}
              className={`relative inline-flex h-5 w-9 items-center rounded-full transition-colors ${autoLaunch ? 'bg-primary-500' : 'bg-gray-200'}`}>
              <span className={`inline-block h-3.5 w-3.5 transform rounded-full bg-white transition-transform ${autoLaunch ? 'translate-x-4.5' : 'translate-x-0.5'}`} />
            </button>
          </div>

          <button onClick={handleSave}
            className="w-full px-3 py-1.5 text-xs bg-primary-500 text-white rounded hover:bg-primary-600 flex items-center justify-center gap-1 transition-colors">
            <Save className="w-3.5 h-3.5" />
            <span>{saved ? 'Saved!' : 'Save'}</span>
          </button>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-sm">
        <div className="p-3 border-b border-gray-100">
          <h2 className="text-xs font-semibold text-gray-900">Schedule Reminders</h2>
        </div>
        <div className="p-3 space-y-3">
          <div>
            <label className="block text-[10px] font-medium text-gray-500 mb-0.5">Minutes before reminder (1-60)</label>
            <input type="number" min="1" max="60" step="1" value={reminderMinutes} onChange={(e) => setReminderMinutes(parseInt(e.target.value))}
              className="w-full px-2 py-1 text-xs border border-gray-200 rounded focus:ring-2 focus:ring-primary-500 focus:border-transparent" />
          </div>
          <div className="flex items-center justify-between py-1">
            <span className="text-xs text-gray-700">Show reminders in widget</span>
            <button onClick={() => setShowWidgetReminders(!showWidgetReminders)}
              className={`relative inline-flex h-5 w-9 items-center rounded-full transition-colors ${showWidgetReminders ? 'bg-primary-500' : 'bg-gray-200'}`}>
              <span className={`inline-block h-3.5 w-3.5 transform rounded-full bg-white transition-transform ${showWidgetReminders ? 'translate-x-4.5' : 'translate-x-0.5'}`} />
            </button>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-sm">
        <div className="p-3 border-b border-gray-100">
          <h2 className="text-xs font-semibold text-gray-900">Shortcuts</h2>
        </div>
        <div className="p-3 space-y-1.5">
          {[['Toggle Timer', 'Ctrl+Shift+T'], ['Lunch Break', 'Ctrl+Shift+L'], ['Floating Widget', 'Ctrl+Shift+W']].map(([label, key]) => (
            <div key={key} className="flex justify-between">
              <span className="text-xs text-gray-600">{label}</span>
              <kbd className="px-1.5 py-0.5 bg-gray-50 border border-gray-200 rounded text-[10px] font-mono text-gray-500">{key}</kbd>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Settings;

