import React, { useState, useEffect } from 'react';
import { Save, Lock, Unlock } from 'lucide-react';
import useSettingsStore from '../stores/settingsStore';

function Settings() {
  const settingsStore = useSettingsStore();
  const [dailyBudget, setDailyBudget] = useState(settingsStore.dailyBudgetHours);
  const [lunchDuration, setLunchDuration] = useState(settingsStore.lunchDurationMinutes);
  const [idleThreshold, setIdleThreshold] = useState(settingsStore.idleThresholdMinutes);
  const [autoPause, setAutoPause] = useState(settingsStore.autoPauseOnIdle);
  const [autoLaunch, setAutoLaunch] = useState(settingsStore.autoLaunch);
  const [reminderMinutes, setReminderMinutes] = useState(settingsStore.reminderMinutesBefore);
  const [showWidgetReminders, setShowWidgetReminders] = useState(settingsStore.showWidgetReminders);
  const [saved, setSaved] = useState(false);
  const [hasPassword, setHasPassword] = useState(false);
  const [currentPw, setCurrentPw] = useState('');
  const [newPw, setNewPw] = useState('');
  const [confirmPw, setConfirmPw] = useState('');
  const [pwError, setPwError] = useState('');
  const [pwSaved, setPwSaved] = useState(false);

  useEffect(() => {
    window.electronAPI.dbGet("SELECT value FROM settings WHERE key = 'manualEntryPassword'", []).then((row) => {
      setHasPassword(!!(row && row.value));
    });
  }, []);

  useEffect(() => {
    setDailyBudget(settingsStore.dailyBudgetHours);
    setLunchDuration(settingsStore.lunchDurationMinutes);
    setIdleThreshold(settingsStore.idleThresholdMinutes);
    setAutoPause(settingsStore.autoPauseOnIdle);
    setAutoLaunch(settingsStore.autoLaunch);
    setReminderMinutes(settingsStore.reminderMinutesBefore);
    setShowWidgetReminders(settingsStore.showWidgetReminders);
  }, [settingsStore]);

  const handleSetPassword = async () => {
    setPwError('');
    if (hasPassword && !currentPw) { setPwError('Enter your current password first'); return; }
    if (newPw.length < 4) { setPwError('Password must be at least 4 characters'); return; }
    if (newPw !== confirmPw) { setPwError('Passwords do not match'); return; }
    if (hasPassword) {
      const row = await window.electronAPI.dbGet("SELECT value FROM settings WHERE key = 'manualEntryPassword'", []);
      if (!row || row.value !== currentPw) { setPwError('Current password is incorrect'); return; }
    }
    await window.electronAPI.dbRun("INSERT OR REPLACE INTO settings (key, value) VALUES ('manualEntryPassword', ?)", [newPw]);
    setHasPassword(true);
    setCurrentPw(''); setNewPw(''); setConfirmPw('');
    setPwSaved(true);
    setTimeout(() => setPwSaved(false), 2000);
  };

  const handleClearPassword = async () => {
    setPwError('');
    if (!currentPw) { setPwError('Enter your current password to remove it'); return; }
    const row = await window.electronAPI.dbGet("SELECT value FROM settings WHERE key = 'manualEntryPassword'", []);
    if (!row || row.value !== currentPw) { setPwError('Current password is incorrect'); return; }
    await window.electronAPI.dbRun("DELETE FROM settings WHERE key = 'manualEntryPassword'", []);
    setHasPassword(false);

