const { contextBridge, ipcRenderer } = require('electron');

contextBridge.exposeInMainWorld('electronAPI', {
  // Database operations
  dbQuery: (sql, params) => ipcRenderer.invoke('db:query', sql, params),
  dbRun: (sql, params) => ipcRenderer.invoke('db:run', sql, params),
  dbGet: (sql, params) => ipcRenderer.invoke('db:get', sql, params),
  dbAll: (sql, params) => ipcRenderer.invoke('db:all', sql, params),

  // Timer operations
  startTimer: (taskId) => ipcRenderer.invoke('timer:start', taskId),
  stopTimer: () => ipcRenderer.invoke('timer:stop'),
  pauseTimer: () => ipcRenderer.invoke('timer:pause'),
  resumeTimer: () => ipcRenderer.invoke('timer:resume'),
  getTimerState: () => ipcRenderer.invoke('timer:getState'),

  // Lunch break
  startLunchBreak: () => ipcRenderer.invoke('lunch:start'),
  stopLunchBreak: () => ipcRenderer.invoke('lunch:stop'),

  // Window operations
  closeWindow: () => ipcRenderer.send('window:close'),
  minimizeWindow: () => ipcRenderer.send('window:minimize'),
  toggleWidget: () => ipcRenderer.send('widget:toggle'),

  // Settings
  setAutoLaunch: (enabled) => ipcRenderer.invoke('settings:autoLaunch', enabled),

  // Schedule operations
  getScheduledTasks: () => ipcRenderer.invoke('schedule:getAll'),
  addScheduledTask: (data) => ipcRenderer.invoke('schedule:add', data),
  updateScheduledTask: (data) => ipcRenderer.invoke('schedule:update', data),
  deleteScheduledTask: (id) => ipcRenderer.invoke('schedule:delete', id),

  // Widget resize
  resizeWidget: (width, height) => ipcRenderer.send('widget:resize', width, height),

  // Event listeners
  onTimerTick: (callback) => {
    const subscription = (event, data) => callback(data);
    ipcRenderer.on('timer:tick', subscription);
    return () => ipcRenderer.removeListener('timer:tick', subscription);
  },

  onTimerState: (callback) => {
    const subscription = (event, data) => callback(data);
    ipcRenderer.on('timer:state', subscription);
    return () => ipcRenderer.removeListener('timer:state', subscription);
  },

  onIdleDetected: (callback) => {
    const subscription = (event, data) => callback(data);
    ipcRenderer.on('idle:detected', subscription);
    return () => ipcRenderer.removeListener('idle:detected', subscription);
  },

  onUpcomingReminders: (callback) => {
    const subscription = (event, data) => callback(data);
    ipcRenderer.on('reminders:upcoming', subscription);
    return () => ipcRenderer.removeListener('reminders:upcoming', subscription);
  },

  onTodaySchedule: (callback) => {
    const subscription = (event, data) => callback(data);
    ipcRenderer.on('reminders:todaySchedule', subscription);
    return () => ipcRenderer.removeListener('reminders:todaySchedule', subscription);
  },
});

