import { app, BrowserWindow, ipcMain, globalShortcut } from 'electron';
import path from 'path';
import { fileURLToPath } from 'url';
import {
  initDatabase,
  closeDatabase,
  query,
  run,
  get,
  all,
} from './database.js';
import {
  startTimer,
  stopTimer,
  pauseTimer,
  resumeTimer,
  getTimerState,
  restoreTimer,
  startLunchBreak,
  stopLunchBreak,
} from './timer.js';
import {
  createMainWindow,
  createFloatingWidget,
  showMainWindow,
  toggleFloatingWidget,
  resizeFloatingWidget,
} from './windows.js';
import { createTray, destroyTray } from './tray.js';
import { startIdleDetection, stopIdleDetection } from './idle.js';
import { startReminderEngine, stopReminderEngine } from './reminders.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Prevent multiple instances
const gotTheLock = app.requestSingleInstanceLock();

if (!gotTheLock) {
  app.quit();
} else {
  app.on('second-instance', () => {
    showMainWindow();
  });

  app.whenReady().then(async () => {
    try {
      // Initialize database
      await initDatabase();

      // Start with floating widget
      createFloatingWidget();

      // Create system tray
      createTray();

      // Restore active timer if exists
      await restoreTimer();

      // Start idle detection
      startIdleDetection();

      // Start reminder engine
      startReminderEngine();

      // Register global shortcuts
      registerGlobalShortcuts();

      console.log('Application started successfully');
    } catch (error) {
      console.error('Failed to start application:', error);
      app.quit();
    }
  });

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      createFloatingWidget();
    }
  });

