import { app, BrowserWindow, ipcMain, globalShortcut } from 'electron';
import path from 'path';
import { fileURLToPath } from 'url';
import {
  initDatabase,
  closeDatabase,
  query,
  run,
  get,
  all,
} from './database.js';
import {
  startTimer,
  stopTimer,
  pauseTimer,
  resumeTimer,
  getTimerState,
  restoreTimer,
  startLunchBreak,
  stopLunchBreak,
} from './timer.js';
import {
  createMainWindow,
  createFloatingWidget,
  showMainWindow,
  toggleFloatingWidget,
  resizeFloatingWidget,
} from './windows.js';
import { createTray, destroyTray } from './tray.js';
import { startIdleDetection, stopIdleDetection } from './idle.js';
import { startReminderEngine, stopReminderEngine } from './reminders.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Prevent multiple instances
const gotTheLock = app.requestSingleInstanceLock();

if (!gotTheLock) {
  app.quit();
} else {
  app.on('second-instance', () => {
    showMainWindow();
  });

  app.whenReady().then(async () => {
    try {
      // Initialize database
      await initDatabase();

      // Start with floating widget
      createFloatingWidget();

      // Create system tray
      createTray();

      // Restore active timer if exists
      await restoreTimer();

      // Start idle detection
      startIdleDetection();

      // Start reminder engine
      startReminderEngine();

      // Register global shortcuts
      registerGlobalShortcuts();

      console.log('Application started successfully');
    } catch (error) {
      console.error('Failed to start application:', error);
      app.quit();
    }
  });

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      createFloatingWidget();
    }
  });

  app.on('before-quit', () => {
    closeDatabase();
    stopIdleDetection();
    stopReminderEngine();
    destroyTray();
    globalShortcut.unregisterAll();
  });

  app.on('window-all-closed', () => {
    // Don't quit on window close (keep running in tray)
    // Uncomment below to quit when all windows are closed
    // if (process.platform !== 'darwin') {
    //   app.quit();
    // }
  });

  // Setup IPC handlers
  setupIpcHandlers();
}

function registerGlobalShortcuts() {
  // Ctrl+Shift+T - Toggle timer
  globalShortcut.register('CommandOrControl+Shift+T', async () => {
    const state = getTimerState();
    if (state.isActive) {
      await stopTimer();
    } else {
      showMainWindow();
    }
  });

  // Ctrl+Shift+L - Start lunch break
  globalShortcut.register('CommandOrControl+Shift+L', async () => {
    await startLunchBreak();
  });

  // Ctrl+Shift+W - Toggle floating widget
  globalShortcut.register('CommandOrControl+Shift+W', () => {
    toggleFloatingWidget();
  });
}

function setupIpcHandlers() {
  // Database operations
  ipcMain.handle('db:query', async (event, sql, params) => {
    try {
      return query(sql, params);
    } catch (error) {
      console.error('IPC db:query error:', error);
      throw error;
    }
  });

  ipcMain.handle('db:run', async (event, sql, params) => {
    try {
      return run(sql, params);
    } catch (error) {
      console.error('IPC db:run error:', error);
      throw error;
    }
  });

  ipcMain.handle('db:get', async (event, sql, params) => {
    try {
      return get(sql, params);
    } catch (error) {
      console.error('IPC db:get error:', error);
      throw error;
    }
  });

  ipcMain.handle('db:all', async (event, sql, params) => {
    try {
      return all(sql, params);
    } catch (error) {
      console.error('IPC db:all error:', error);
      throw error;
    }
  });

  // Timer operations
  ipcMain.handle('timer:start', async (event, taskId) => {
    try {
      return await startTimer(taskId);
    } catch (error) {
      console.error('IPC timer:start error:', error);
      throw error;
    }
  });

  ipcMain.handle('timer:stop', async () => {
    try {
      return await stopTimer();
    } catch (error) {
      console.error('IPC timer:stop error:', error);
      throw error;
    }
  });

  ipcMain.handle('timer:pause', async () => {
    try {
      return await pauseTimer();
    } catch (error) {
      console.error('IPC timer:pause error:', error);
      throw error;
    }
  });

  ipcMain.handle('timer:resume', async () => {
    try {
      return await resumeTimer();
    } catch (error) {
      console.error('IPC timer:resume error:', error);
      throw error;
    }
  });

  ipcMain.handle('timer:getState', () => {
    return getTimerState();
  });

  // Lunch break
  ipcMain.handle('lunch:start', async () => {
    try {
      return await startLunchBreak();
    } catch (error) {
      console.error('IPC lunch:start error:', error);
      throw error;
    }
  });

  ipcMain.handle('lunch:stop', async () => {
    try {
      return await stopLunchBreak();
    } catch (error) {
      console.error('IPC lunch:stop error:', error);
      throw error;
    }
  });

  // Window operations
  ipcMain.on('window:close', (event) => {
    const window = BrowserWindow.fromWebContents(event.sender);
    if (window) {
      window.close();
    }
  });

  ipcMain.on('window:minimize', (event) => {
    const window = BrowserWindow.fromWebContents(event.sender);
    if (window) {
      window.minimize();
    }
  });

  ipcMain.on('widget:toggle', () => {
    toggleFloatingWidget();
  });

  // Settings
  ipcMain.handle('settings:autoLaunch', async (event, enabled) => {
    try {
      app.setLoginItemSettings({
        openAtLogin: enabled,
        openAsHidden: false,
      });
      return { success: true };
    } catch (error) {
      console.error('IPC settings:autoLaunch error:', error);
      throw error;
    }
  });

  // Schedule operations
  ipcMain.handle('schedule:getAll', async () => {
    try {
      return all(
        `SELECT st.*, t.name as task_name, p.name as project_name, c.name as customer_name
         FROM scheduled_tasks st
         JOIN tasks t ON st.task_id = t.id
         JOIN projects p ON t.project_id = p.id
         JOIN customers c ON p.customer_id = c.id
         WHERE st.is_active = 1
         ORDER BY st.start_time`,
        []
      );
    } catch (error) {
      console.error('IPC schedule:getAll error:', error);
      throw error;
    }
  });

  ipcMain.handle('schedule:add', async (event, data) => {
    try {
      return run(
        `INSERT INTO scheduled_tasks (task_id, day_of_week, specific_date, start_time, end_time, recurrence_type, recurrence_pattern)
         VALUES (?, ?, ?, ?, ?, ?, ?)`,
        [data.task_id, data.day_of_week, data.specific_date, data.start_time, data.end_time, data.recurrence_type, data.recurrence_pattern]
      );
    } catch (error) {
      console.error('IPC schedule:add error:', error);
      throw error;
    }
  });

  ipcMain.handle('schedule:update', async (event, data) => {
    try {
      return run(
        `UPDATE scheduled_tasks SET task_id = ?, day_of_week = ?, specific_date = ?, start_time = ?, end_time = ?, recurrence_type = ?, recurrence_pattern = ?
         WHERE id = ?`,
        [data.task_id, data.day_of_week, data.specific_date, data.start_time, data.end_time, data.recurrence_type, data.recurrence_pattern, data.id]
      );
    } catch (error) {
      console.error('IPC schedule:update error:', error);
      throw error;
    }
  });

  ipcMain.handle('schedule:delete', async (event, id) => {
    try {
      return run('UPDATE scheduled_tasks SET is_active = 0 WHERE id = ?', [id]);
    } catch (error) {
      console.error('IPC schedule:delete error:', error);
      throw error;
    }
  });

  // Widget resize
  ipcMain.on('widget:resize', (event, width, height) => {
    resizeFloatingWidget(width, height);
  });
}

