    const window = BrowserWindow.fromWebContents(event.sender);
    if (window) {
      window.close();
    }
  });

  ipcMain.on('window:minimize', (event) => {
    const window = BrowserWindow.fromWebContents(event.sender);
    if (window) {
      window.minimize();
    }
  });

  ipcMain.on('widget:toggle', () => {
    toggleFloatingWidget();
  });

  // Settings
  ipcMain.handle('settings:autoLaunch', async (event, enabled) => {
    try {
      app.setLoginItemSettings({
        openAtLogin: enabled,
        openAsHidden: false,
      });
      return { success: true };
    } catch (error) {
      console.error('IPC settings:autoLaunch error:', error);
      throw error;
    }
  });

  // Schedule operations
  ipcMain.handle('schedule:getAll', async () => {
    try {
      return all(
        `SELECT st.*, t.name as task_name, p.name as project_name, c.name as customer_name
         FROM scheduled_tasks st
         JOIN tasks t ON st.task_id = t.id
         JOIN projects p ON t.project_id = p.id
         JOIN customers c ON p.customer_id = c.id
         WHERE st.is_active = 1
         ORDER BY st.start_time`,
        []
      );
    } catch (error) {
      console.error('IPC schedule:getAll error:', error);
      throw error;
    }
  });

  ipcMain.handle('schedule:add', async (event, data) => {
    try {
      return run(
        `INSERT INTO scheduled_tasks (task_id, day_of_week, specific_date, start_time, end_time, recurrence_type, recurrence_pattern)
         VALUES (?, ?, ?, ?, ?, ?, ?)`,
        [data.task_id, data.day_of_week, data.specific_date, data.start_time, data.end_time, data.recurrence_type, data.recurrence_pattern]
      );
    } catch (error) {
      console.error('IPC schedule:add error:', error);
      throw error;
    }
  });

  ipcMain.handle('schedule:update', async (event, data) => {
    try {
      return run(
        `UPDATE scheduled_tasks SET task_id = ?, day_of_week = ?, specific_date = ?, start_time = ?, end_time = ?, recurrence_type = ?, recurrence_pattern = ?
         WHERE id = ?`,
        [data.task_id, data.day_of_week, data.specific_date, data.start_time, data.end_time, data.recurrence_type, data.recurrence_pattern, data.id]
      );
    } catch (error) {
      console.error('IPC schedule:update error:', error);
      throw error;
    }
  });

  ipcMain.handle('schedule:delete', async (event, id) => {
    try {
      return run('UPDATE scheduled_tasks SET is_active = 0 WHERE id = ?', [id]);
    } catch (error) {
      console.error('IPC schedule:delete error:', error);
      throw error;
    }
  });

  // Widget resize
  ipcMain.on('widget:resize', (event, width, height) => {
    resizeFloatingWidget(width, height);
  });
}

