1	import React, { useState, useEffect } from 'react';
2	import { ChevronLeft, ChevronRight, Download, BarChart3, List, LayoutGrid } from 'lucide-react';
3	import { getWeekBounds, formatDateShort, formatDuration } from '../utils/formatTime';
4	
5	function WeeklyReport() {
6	  const [currentWeekStart, setCurrentWeekStart] = useState(() => getWeekBounds().start);
7	  const [weekData, setWeekData] = useState([]);
8	  const [detailData, setDetailData] = useState([]);
9	  const [customerWeekData, setCustomerWeekData] = useState(null); // { customers, weeks }
10	  const [weeksToShow, setWeeksToShow] = useState(8);
11	  const [loading, setLoading] = useState(false);
12	  const [viewMode, setViewMode] = useState('summary'); // 'summary' | 'detailed' | 'customer-week'
13	
14	  useEffect(() => {
15	    if (viewMode === 'customer-week') {
16	      loadCustomerWeekData();
17	    } else {
18	      loadWeekData();
19	    }
20	  }, [currentWeekStart, viewMode, weeksToShow]);
21	
22	  const loadWeekData = async () => {
23	    try {
24	      setLoading(true);
25	      const weekEnd = new Date(currentWeekStart);
26	      weekEnd.setDate(weekEnd.getDate() + 6);
27	      weekEnd.setHours(23, 59, 59, 999);
28	
29	      const entries = await window.electronAPI.dbAll(
30	        `SELECT te.*, t.name as task_name, p.name as project_name, c.name as customer_name, p.id as project_id, c.id as customer_id
31	         FROM time_entries te LEFT JOIN tasks t ON te.task_id = t.id LEFT JOIN projects p ON t.project_id = p.id LEFT JOIN customers c ON p.customer_id = c.id
32	         WHERE te.start_time >= ? AND te.start_time <= ? ORDER BY c.name, p.name, t.name, te.start_time`,
33	        [currentWeekStart.toISOString(), weekEnd.toISOString()]
34	      );
35	
36	      // Summary: grouped by customer > project > task with daily totals
37	      const grouped = {};
38	      entries.forEach((entry) => {
39	        const customerKey = entry.is_lunch_break ? 'System' : (entry.customer_name || 'No Customer');
40	        const rowKey = entry.is_lunch_break ? 'Lunch Break' : `${entry.project_name}|${entry.task_name}`;
41	
42	        if (!grouped[customerKey]) {
43	          grouped[customerKey] = { customerName: customerKey, rows: {}, isSystem: entry.is_lunch_break === 1 };
44	        }
45	        if (!grouped[customerKey].rows[rowKey]) {
46	          grouped[customerKey].rows[rowKey] = { project: entry.project_name || '-', task: entry.task_name || 'Lunch Break', isLunch: entry.is_lunch_break === 1, days: [0,0,0,0,0,0,0], total: 0 };
47	        }
48	        const entryDate = new Date(entry.start_time);
49	        const dayOfWeek = entryDate.getDay();
50	        const dayIndex = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
51	        const duration = entry.duration_seconds || 0;
52	        grouped[customerKey].rows[rowKey].days[dayIndex] += duration;
53	        grouped[customerKey].rows[rowKey].total += duration;
54	      });
55	
56	      const customerData = Object.entries(grouped).map(([customerName, data]) => ({
57	        customerName,
58	        isSystem: data.isSystem,
59	        rows: Object.values(data.rows)
60	      })).sort((a, b) => {
61	        if (a.isSystem) return 1;
62	        if (b.isSystem) return -1;
63	        return a.customerName.localeCompare(b.customerName);
64	      });
65	
66	      setWeekData(customerData);
67	
68	      // Detailed: grouped by customer > project|task rows, each day cell has entry list
69	      const detailGrouped = {};
70	      entries.forEach((entry) => {
71	        const customerKey = entry.is_lunch_break ? 'System' : (entry.customer_name || 'No Customer');
72	        const rowKey = entry.is_lunch_break ? 'Lunch Break' : `${entry.project_name}|${entry.task_name}`;
73	        if (!detailGrouped[customerKey]) {
74	          detailGrouped[customerKey] = { customerName: customerKey, isSystem: entry.is_lunch_break === 1, rows: {} };
75	        }
76	        if (!detailGrouped[customerKey].rows[rowKey]) {
77	          detailGrouped[customerKey].rows[rowKey] = {
78	            project: entry.is_lunch_break ? '-' : (entry.project_name || '-'),
79	            task: entry.is_lunch_break ? 'Lunch Break' : (entry.task_name || '-'),
80	            isLunch: entry.is_lunch_break === 1,
81	            days: Array.from({ length: 7 }, () => []),
82	            total: 0,
83	          };
84	        }
85	        const entryDate = new Date(entry.start_time);
86	        const dayOfWeek = entryDate.getDay();
87	        const dayIndex = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
88	        const duration = entry.duration_seconds || 0;
89	        detailGrouped[customerKey].rows[rowKey].days[dayIndex].push({
90	          start_time: entry.start_time,
91	          end_time: entry.end_time,
92	          duration,
93	        });
94	        detailGrouped[customerKey].rows[rowKey].total += duration;
95	      });
96	
97	      const detailArr = Object.entries(detailGrouped).map(([customerName, data]) => ({
98	        customerName,
99	        isSystem: data.isSystem,
100	        rows: Object.values(data.rows),
101	      })).sort((a, b) => {
102	        if (a.isSystem) return 1;
103	        if (b.isSystem) return -1;
104	        return a.customerName.localeCompare(b.customerName);
105	      });
106	
107	      setDetailData(detailArr);
108	      setLoading(false);
109	    } catch (error) { console.error('Error loading week data:', error); setLoading(false); }
110	  };
111	
112	  const loadCustomerWeekData = async () => {
113	    try {
114	      setLoading(true);
115	      // Range: (weeksToShow - 1) weeks back from currentWeekStart through end of currentWeek
116	      const rangeStart = new Date(currentWeekStart);
117	      rangeStart.setDate(rangeStart.getDate() - (weeksToShow - 1) * 7);
118	
119	      const rangeEnd = new Date(currentWeekStart);
120	      rangeEnd.setDate(rangeEnd.getDate() + 6);
121	      rangeEnd.setHours(23, 59, 59, 999);
122	
123	      const entries = await window.electronAPI.dbAll(
124	        `SELECT te.duration_seconds, te.start_time, c.name as customer_name
125	         FROM time_entries te
126	         LEFT JOIN tasks t ON te.task_id = t.id
127	         LEFT JOIN projects p ON t.project_id = p.id
128	         LEFT JOIN customers c ON p.customer_id = c.id
129	         WHERE te.start_time >= ? AND te.start_time <= ? AND te.is_lunch_break = 0
130	         ORDER BY c.name, te.start_time`,
131	        [rangeStart.toISOString(), rangeEnd.toISOString()]
132	      );
133	
134	      // Build weeks array oldest → newest
135	      const weeks = [];
136	      for (let i = weeksToShow - 1; i >= 0; i--) {
137	        const ws = new Date(currentWeekStart);
138	        ws.setDate(ws.getDate() - i * 7);
139	        weeks.push(ws);
140	      }
141	
142	      // Group by customer + week index
143	      const customerMap = {};
144	      entries.forEach((entry) => {
145	        const customerKey = entry.customer_name || 'No Customer';
146	        const entryDate = new Date(entry.start_time);
147	        const weekIdx = weeks.findIndex((ws) => {
148	          const we = new Date(ws);
149	          we.setDate(we.getDate() + 6);
150	          we.setHours(23, 59, 59, 999);
151	          return entryDate >= ws && entryDate <= we;
152	        });
153	        if (weekIdx === -1) return;
154	
155	        if (!customerMap[customerKey]) {
156	          customerMap[customerKey] = { customerName: customerKey, weeks: new Array(weeksToShow).fill(0), total: 0 };
157	        }
158	        const duration = entry.duration_seconds || 0;
159	        customerMap[customerKey].weeks[weekIdx] += duration;
160	        customerMap[customerKey].total += duration;
161	      });
162	
163	      const customers = Object.values(customerMap).sort((a, b) => a.customerName.localeCompare(b.customerName));
164	      setCustomerWeekData({ customers, weeks });
165	      setLoading(false);
166	    } catch (error) { console.error('Error loading customer week data:', error); setLoading(false); }
167	  };
168	
169	  const previousWeek = () => { const d = new Date(currentWeekStart); d.setDate(d.getDate() - 7); setCurrentWeekStart(d); };
170	  const nextWeek = () => { const d = new Date(currentWeekStart); d.setDate(d.getDate() + 7); setCurrentWeekStart(d); };
171	  const currentWeek = () => { setCurrentWeekStart(getWeekBounds().start); };
172	
173	  const downloadCSV = (content, filename) => {
174	    const blob = new Blob([content], { type: 'text/csv' });
175	    const url = URL.createObjectURL(blob);
176	    const a = document.createElement('a'); a.href = url; a.download = filename; a.click(); URL.revokeObjectURL(url);
177	  };
178	
179	  const exportSummaryCSV = () => {
180	    let csv = 'Customer,Project,Task,Mon,Tue,Wed,Thu,Fri,Sat,Sun,Total\n';
181	    weekData.forEach((customer) => {
182	      customer.rows.forEach((row) => {
183	        csv += `"${customer.customerName}","${row.project}","${row.task}",${row.days.map((s) => (s/3600).toFixed(2)).join(',')},${(row.total/3600).toFixed(2)}\n`;
184	      });
185	    });
186	    downloadCSV(csv, `timesheet-summary-${formatDateShort(currentWeekStart)}.csv`);
187	  };
188	
189	  const exportDetailedCSV = () => {
190	    const fmtTime = (iso) => {
191	      if (!iso) return '';
192	      const d = new Date(iso);
193	      return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false });
194	    };
195	    let csv = 'Customer,Project,Task';
196	    dayNames.forEach((d) => { csv += `,${d}`; });
197	    csv += ',Total\n';
198	    detailData.forEach((customer) => {
199	      customer.rows.forEach((row) => {
200	        csv += `"${customer.customerName}","${row.project}","${row.task}"`;
201	        row.days.forEach((entries) => {
202	          if (entries.length === 0) {
203	            csv += ',-';
204	          } else {
205	            const cellStr = entries.map((e) => `${fmtTime(e.start_time)}-${e.end_time ? fmtTime(e.end_time) : '...'}`).join(' | ');
206	            csv += `,"${cellStr}"`;
207	          }
208	        });
209	        csv += `,${(row.total/3600).toFixed(2)}\n`;
210	      });
211	    });
212	    downloadCSV(csv, `timesheet-detailed-${formatDateShort(currentWeekStart)}.csv`);
213	  };
214	
215	  const exportCustomerWeekCSV = () => {
216	    if (!customerWeekData) return;
217	    const { customers, weeks } = customerWeekData;
218	    const weekLabels = weeks.map((ws) => {
219	      const we = new Date(ws); we.setDate(we.getDate() + 6);
220	      return `${formatDateShort(ws)}-${formatDateShort(we)}`;
221	    });
222	    let csv = `Customer,${weekLabels.map((l) => `"${l}"`).join(',')},Total\n`;
223	    customers.forEach((c) => {
224	      csv += `"${c.customerName}",${c.weeks.map((s) => (s/3600).toFixed(2)).join(',')},${(c.total/3600).toFixed(2)}\n`;
225	    });
226	    // Totals row
227	    const weekTotals = new Array(weeks.length).fill(0);
228	    let grandTotal = 0;
229	    customers.forEach((c) => { c.weeks.forEach((s, i) => { weekTotals[i] += s; }); grandTotal += c.total; });
230	    csv += `"Total",${weekTotals.map((s) => (s/3600).toFixed(2)).join(',')},${(grandTotal/3600).toFixed(2)}\n`;
231	    downloadCSV(csv, `timesheet-by-customer-week-${formatDateShort(currentWeekStart)}.csv`);
232	  };
233	
234	  const handleExport = () => {
235	    if (viewMode === 'summary') exportSummaryCSV();
236	    else if (viewMode === 'detailed') exportDetailedCSV();
237	    else exportCustomerWeekCSV();
238	  };
239	
240	  const weekEnd = new Date(currentWeekStart); weekEnd.setDate(weekEnd.getDate() + 6);
241	  const dayNames = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
242	
243	  const grandColumnTotals = [0,0,0,0,0,0,0];
244	  let overallTotal = 0;
245	  weekData.forEach((customer) => {
246	    customer.rows.forEach((row) => {
247	      if (!row.isLunch) {
248	        row.days.forEach((s, i) => { grandColumnTotals[i] += s; });
249	        overallTotal += row.total;
250	      }
251	    });
252	  });
253	
254	  const formatDateTime = (iso) => {
255	    if (!iso) return '-';
256	    const d = new Date(iso);
257	    return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
258	  };
259	
260	  return (
261	    <div className="max-w-7xl mx-auto">
262	      <div className="bg-white rounded-lg shadow-sm">
263	        <div className="p-3 border-b border-gray-100">
264	          <div className="flex items-center justify-between mb-2">
265	            <h2 className="text-sm font-semibold text-gray-900">Weekly Report</h2>
266	            <div className="flex items-center gap-2">
267	              {/* View toggle */}
268	              <div className="flex items-center bg-gray-100 rounded overflow-hidden">
269	                <button onClick={() => setViewMode('summary')}
270	                  className={`px-2 py-1 text-xs flex items-center gap-1 transition-colors ${viewMode === 'summary' ? 'bg-primary-500 text-white' : 'text-gray-600 hover:bg-gray-200'}`}>
271	                  <BarChart3 className="w-3 h-3" /> Summary
272	                </button>
273	                <button onClick={() => setViewMode('detailed')}
274	                  className={`px-2 py-1 text-xs flex items-center gap-1 transition-colors ${viewMode === 'detailed' ? 'bg-primary-500 text-white' : 'text-gray-600 hover:bg-gray-200'}`}>
275	                  <List className="w-3 h-3" /> Detailed
276	                </button>
277	                <button onClick={() => setViewMode('customer-week')}
278	                  className={`px-2 py-1 text-xs flex items-center gap-1 transition-colors ${viewMode === 'customer-week' ? 'bg-primary-500 text-white' : 'text-gray-600 hover:bg-gray-200'}`}>
279	                  <LayoutGrid className="w-3 h-3" /> By Customer
280	                </button>
281	              </div>
282	              {/* CSV download */}
283	              <button onClick={handleExport}
284	                className="px-2.5 py-1 text-xs bg-emerald-500 text-white rounded hover:bg-emerald-600 flex items-center gap-1 transition-colors">
285	                <Download className="w-3 h-3" /><span>CSV</span>
286	              </button>
287	            </div>
288	          </div>
289	
290	          {viewMode === 'customer-week' ? (
291	            /* Customer-week controls: weeks selector + end-week navigation */
292	            <div className="flex items-center justify-center gap-3">
293	              <button onClick={previousWeek} className="p-1 hover:bg-gray-100 rounded"><ChevronLeft className="w-4 h-4 text-gray-500" /></button>
294	              <div className="text-center">
295	                <div className="text-xs font-medium text-gray-900">Ending {formatDateShort(weekEnd)}</div>
296	                <button onClick={currentWeek} className="text-[10px] text-primary-500 hover:text-primary-600">Current Week</button>
297	              </div>
298	              <button onClick={nextWeek} className="p-1 hover:bg-gray-100 rounded"><ChevronRight className="w-4 h-4 text-gray-500" /></button>
299	              <div className="flex items-center gap-1 ml-2">
300	                <span className="text-[10px] text-gray-500">Show</span>
301	                <select value={weeksToShow} onChange={(e) => setWeeksToShow(Number(e.target.value))}
302	                  className="text-xs border border-gray-200 rounded px-1 py-0.5 text-gray-700 bg-white">
303	                  <option value={4}>4 weeks</option>
304	                  <option value={8}>8 weeks</option>
305	                  <option value={12}>12 weeks</option>
306	                  <option value={24}>24 weeks</option>
307	                </select>
308	              </div>
309	            </div>
310	          ) : (
311	            /* Standard week navigation */
312	            <div className="flex items-center justify-center gap-3">
313	              <button onClick={previousWeek} className="p-1 hover:bg-gray-100 rounded"><ChevronLeft className="w-4 h-4 text-gray-500" /></button>
314	              <div className="text-center min-w-[200px]">
315	                <div className="text-xs font-medium text-gray-900">{formatDateShort(currentWeekStart)} - {formatDateShort(weekEnd)}</div>
316	                <button onClick={currentWeek} className="text-[10px] text-primary-500 hover:text-primary-600">Current Week</button>
317	              </div>
318	              <button onClick={nextWeek} className="p-1 hover:bg-gray-100 rounded"><ChevronRight className="w-4 h-4 text-gray-500" /></button>
319	            </div>
320	          )}
321	        </div>
322	
323	        <div className="overflow-x-auto">
324	          {loading ? (
325	            <div className="p-4 text-center text-gray-400 text-xs">Loading...</div>
326	          ) : viewMode === 'customer-week' ? (
327	            /* ===== CUSTOMER & WEEK VIEW ===== */
328	            !customerWeekData || customerWeekData.customers.length === 0 ? (
329	              <div className="p-4 text-center text-gray-400 text-xs">No entries in this period</div>
330	            ) : (
331	              <div className="p-4">
332	                <div className="border border-gray-200 rounded-lg overflow-hidden">
333	                  <table className="w-full text-xs">
334	                    <thead className="bg-gray-50 border-b border-gray-100">
335	                      <tr>
336	                        <th className="px-3 py-1.5 text-left font-medium text-gray-500 sticky left-0 bg-gray-50">Customer</th>
337	                        {customerWeekData.weeks.map((ws, i) => {
338	                          const we = new Date(ws); we.setDate(we.getDate() + 6);
339	                          return (
340	                            <th key={i} className="px-2 py-1.5 text-right font-medium text-gray-500 whitespace-nowrap">
341	                              {formatDateShort(ws)}
342	                            </th>
343	                          );
344	                        })}
345	                        <th className="px-2 py-1.5 text-right font-medium text-gray-500">Total</th>
346	                      </tr>
347	                    </thead>
348	                    <tbody className="divide-y divide-gray-50">
349	                      {customerWeekData.customers.map((customer, ci) => (
350	                        <tr key={ci} className="hover:bg-gray-50">
351	                          <td className="px-3 py-1.5 font-medium text-gray-900 sticky left-0 bg-white">{customer.customerName}</td>
352	                          {customer.weeks.map((seconds, wi) => (
353	                            <td key={wi} className="px-2 py-1.5 text-right font-mono text-gray-500">
354	                              {seconds > 0 ? formatDuration(seconds) : <span className="text-gray-200">-</span>}
355	                            </td>
356	                          ))}
357	                          <td className="px-2 py-1.5 text-right font-mono font-semibold text-gray-900">{formatDuration(customer.total)}</td>
358	                        </tr>
359	                      ))}
360	                      {/* Weekly totals row */}
361	                      {(() => {
362	                        const weekTotals = new Array(customerWeekData.weeks.length).fill(0);
363	                        let grandTotal = 0;
364	                        customerWeekData.customers.forEach((c) => {
365	                          c.weeks.forEach((s, i) => { weekTotals[i] += s; });
366	                          grandTotal += c.total;
367	                        });
368	                        return (
369	                          <tr className="bg-emerald-50 font-bold border-t-2 border-emerald-200">
370	                            <td className="px-3 py-2 text-gray-900 sticky left-0 bg-emerald-50">Total</td>
371	                            {weekTotals.map((s, i) => (
372	                              <td key={i} className="px-2 py-2 text-right font-mono text-gray-900">{s > 0 ? formatDuration(s) : <span className="text-gray-300">-</span>}</td>
373	                            ))}
374	                            <td className="px-2 py-2 text-right font-mono text-gray-900">{formatDuration(grandTotal)}</td>
375	                          </tr>
376	                        );
377	                      })()}
378	                    </tbody>
379	                  </table>
380	                </div>
381	              </div>
382	            )
383	          ) : (weekData.length === 0 && detailData.length === 0) ? (
384	            <div className="p-4 text-center text-gray-400 text-xs">No entries this week</div>
385	          ) : viewMode === 'summary' ? (
386	            /* ===== SUMMARY VIEW ===== */
387	            <div className="space-y-4 p-4">
388	              {weekData.map((customer, customerIndex) => {
389	                const customerColumnTotals = [0,0,0,0,0,0,0];
390	                let customerTotal = 0;
391	                customer.rows.forEach((row) => {
392	                  if (!row.isLunch) {
393	                    row.days.forEach((s, i) => { customerColumnTotals[i] += s; });
394	                    customerTotal += row.total;
395	                  }
396	                });
397	
398	                return (
399	                  <div key={customerIndex} className="border border-gray-200 rounded-lg overflow-hidden">
400	                    <div className="bg-gray-100 px-3 py-2 border-b border-gray-200">
401	                      <h3 className="text-sm font-semibold text-gray-900">{customer.customerName}</h3>
402	                    </div>
403	                    <table className="w-full text-xs">
404	                      <thead className="bg-gray-50 border-b border-gray-100">
405	                        <tr>
406	                          <th className="px-2 py-1.5 text-left font-medium text-gray-500">Project</th>
407	                          <th className="px-2 py-1.5 text-left font-medium text-gray-500">Task</th>
408	                          {dayNames.map((day) => <th key={day} className="px-2 py-1.5 text-right font-medium text-gray-500">{day}</th>)}
409	                          <th className="px-2 py-1.5 text-right font-medium text-gray-500">Total</th>
410	                        </tr>
411	                      </thead>
412	                      <tbody className="divide-y divide-gray-50">
413	                        {customer.rows.map((row, rowIndex) => (
414	                          <tr key={rowIndex} className={row.isLunch ? 'bg-amber-50' : 'hover:bg-gray-50'}>
415	                            <td className="px-2 py-1.5 text-gray-900">{row.project}</td>
416	                            <td className="px-2 py-1.5 text-gray-900">{row.task}</td>
417	                            {row.days.map((seconds, di) => <td key={di} className="px-2 py-1.5 text-right font-mono text-gray-500">{seconds > 0 ? formatDuration(seconds) : '-'}</td>)}
418	                            <td className="px-2 py-1.5 text-right font-mono font-medium text-gray-900">{formatDuration(row.total)}</td>
419	                          </tr>
420	                        ))}
421	                        <tr className="bg-gray-50 font-semibold">
422	                          <td colSpan="2" className="px-2 py-1.5 text-gray-900">Subtotal (excl. lunch)</td>
423	                          {customerColumnTotals.map((s, i) => <td key={i} className="px-2 py-1.5 text-right font-mono text-gray-900">{s > 0 ? formatDuration(s) : '-'}</td>)}
424	                          <td className="px-2 py-1.5 text-right font-mono text-gray-900">{formatDuration(customerTotal)}</td>
425	                        </tr>
426	                      </tbody>
427	                    </table>
428	                  </div>
429	                );
430	              })}
431	
432	              {/* Grand Total */}
433	              <div className="border-t-2 border-gray-300 pt-2">
434	                <div className="bg-emerald-50 border border-emerald-200 rounded-lg overflow-hidden">
435	                  <table className="w-full text-xs">
436	                    <tbody>
437	                      <tr className="font-bold">
438	                        <td colSpan="2" className="px-3 py-2 text-gray-900">Grand Total (excl. lunch)</td>
439	                        {grandColumnTotals.map((s, i) => <td key={i} className="px-2 py-2 text-right font-mono text-gray-900">{s > 0 ? formatDuration(s) : '-'}</td>)}
440	                        <td className="px-2 py-2 text-right font-mono text-gray-900">{formatDuration(overallTotal)}</td>
441	                      </tr>
442	                    </tbody>
443	                  </table>
444	                </div>
445	              </div>
446	            </div>
