import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Download, BarChart3, List, LayoutGrid } from 'lucide-react';
import { getWeekBounds, formatDateShort, formatDuration } from '../utils/formatTime';

function WeeklyReport() {
  const [currentWeekStart, setCurrentWeekStart] = useState(() => getWeekBounds().start);
  const [weekData, setWeekData] = useState([]);
  const [detailData, setDetailData] = useState([]);
  const [customerWeekData, setCustomerWeekData] = useState(null); // { customers, weeks }
  const [weeksToShow, setWeeksToShow] = useState(8);
  const [loading, setLoading] = useState(false);
  const [viewMode, setViewMode] = useState('summary'); // 'summary' | 'detailed' | 'customer-week'

  useEffect(() => {
    if (viewMode === 'customer-week') {
      loadCustomerWeekData();
    } else {
      loadWeekData();
    }
  }, [currentWeekStart, viewMode, weeksToShow]);

  const loadWeekData = async () => {
    try {
      setLoading(true);
      const weekEnd = new Date(currentWeekStart);
      weekEnd.setDate(weekEnd.getDate() + 6);
      weekEnd.setHours(23, 59, 59, 999);

      const entries = await window.electronAPI.dbAll(
        `SELECT te.*, t.name as task_name, p.name as project_name, c.name as customer_name, p.id as project_id, c.id as customer_id
         FROM time_entries te LEFT JOIN tasks t ON te.task_id = t.id LEFT JOIN projects p ON t.project_id = p.id LEFT JOIN customers c ON p.customer_id = c.id
         WHERE te.start_time >= ? AND te.start_time <= ? ORDER BY c.name, p.name, t.name, te.start_time`,
        [currentWeekStart.toISOString(), weekEnd.toISOString()]
      );

      // Summary: grouped by customer > project > task with daily totals
      const grouped = {};
      entries.forEach((entry) => {
        const customerKey = entry.is_lunch_break ? 'System' : (entry.customer_name || 'No Customer');
        const rowKey = entry.is_lunch_break ? 'Lunch Break' : `${entry.project_name}|${entry.task_name}`;

        if (!grouped[customerKey]) {
          grouped[customerKey] = { customerName: customerKey, rows: {}, isSystem: entry.is_lunch_break === 1 };
        }
        if (!grouped[customerKey].rows[rowKey]) {
          grouped[customerKey].rows[rowKey] = { project: entry.project_name || '-', task: entry.task_name || 'Lunch Break', isLunch: entry.is_lunch_break === 1, days: [0,0,0,0,0,0,0], total: 0 };
        }
        const entryDate = new Date(entry.start_time);
        const dayOfWeek = entryDate.getDay();
        const dayIndex = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
        const duration = entry.duration_seconds || 0;
        grouped[customerKey].rows[rowKey].days[dayIndex] += duration;
        grouped[customerKey].rows[rowKey].total += duration;
      });

      const customerData = Object.entries(grouped).map(([customerName, data]) => ({
        customerName,
        isSystem: data.isSystem,
        rows: Object.values(data.rows)
      })).sort((a, b) => {
        if (a.isSystem) return 1;
        if (b.isSystem) return -1;
        return a.customerName.localeCompare(b.customerName);
      });

      setWeekData(customerData);

      // Detailed: grouped by customer > project|task rows, each day cell has entry list
      const detailGrouped = {};
      entries.forEach((entry) => {
        const customerKey = entry.is_lunch_break ? 'System' : (entry.customer_name || 'No Customer');
        const rowKey = entry.is_lunch_break ? 'Lunch Break' : `${entry.project_name}|${entry.task_name}`;
        if (!detailGrouped[customerKey]) {
          detailGrouped[customerKey] = { customerName: customerKey, isSystem: entry.is_lunch_break === 1, rows: {} };
        }
        if (!detailGrouped[customerKey].rows[rowKey]) {
          detailGrouped[customerKey].rows[rowKey] = {
            project: entry.is_lunch_break ? '-' : (entry.project_name || '-'),
            task: entry.is_lunch_break ? 'Lunch Break' : (entry.task_name || '-'),
            isLunch: entry.is_lunch_break === 1,
            days: Array.from({ length: 7 }, () => []),
            total: 0,
          };
        }
        const entryDate = new Date(entry.start_time);
        const dayOfWeek = entryDate.getDay();
        const dayIndex = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
        const duration = entry.duration_seconds || 0;
        detailGrouped[customerKey].rows[rowKey].days[dayIndex].push({
          start_time: entry.start_time,
          end_time: entry.end_time,
          duration,
        });
        detailGrouped[customerKey].rows[rowKey].total += duration;
      });

      const detailArr = Object.entries(detailGrouped).map(([customerName, data]) => ({
        customerName,
        isSystem: data.isSystem,
        rows: Object.values(data.rows),
      })).sort((a, b) => {
        if (a.isSystem) return 1;
        if (b.isSystem) return -1;
        return a.customerName.localeCompare(b.customerName);
      });

      setDetailData(detailArr);
      setLoading(false);
    } catch (error) { console.error('Error loading week data:', error); setLoading(false); }
  };

  const loadCustomerWeekData = async () => {
    try {
      setLoading(true);
      // Range: (weeksToShow - 1) weeks back from currentWeekStart through end of currentWeek
      const rangeStart = new Date(currentWeekStart);
      rangeStart.setDate(rangeStart.getDate() - (weeksToShow - 1) * 7);

      const rangeEnd = new Date(currentWeekStart);
      rangeEnd.setDate(rangeEnd.getDate() + 6);
      rangeEnd.setHours(23, 59, 59, 999);

      const entries = await window.electronAPI.dbAll(
        `SELECT te.duration_seconds, te.start_time, c.name as customer_name
         FROM time_entries te
         LEFT JOIN tasks t ON te.task_id = t.id
         LEFT JOIN projects p ON t.project_id = p.id
         LEFT JOIN customers c ON p.customer_id = c.id
         WHERE te.start_time >= ? AND te.start_time <= ? AND te.is_lunch_break = 0
         ORDER BY c.name, te.start_time`,
        [rangeStart.toISOString(), rangeEnd.toISOString()]
      );

      // Build weeks array oldest → newest
      const weeks = [];
      for (let i = weeksToShow - 1; i >= 0; i--) {
        const ws = new Date(currentWeekStart);
        ws.setDate(ws.getDate() - i * 7);
        weeks.push(ws);
      }

      // Group by customer + week index
      const customerMap = {};
      entries.forEach((entry) => {
        const customerKey = entry.customer_name || 'No Customer';
        const entryDate = new Date(entry.start_time);
        const weekIdx = weeks.findIndex((ws) => {
          const we = new Date(ws);
          we.setDate(we.getDate() + 6);
          we.setHours(23, 59, 59, 999);
          return entryDate >= ws && entryDate <= we;
        });
        if (weekIdx === -1) return;

        if (!customerMap[customerKey]) {
          customerMap[customerKey] = { customerName: customerKey, weeks: new Array(weeksToShow).fill(0), total: 0 };
        }
        const duration = entry.duration_seconds || 0;
        customerMap[customerKey].weeks[weekIdx] += duration;
        customerMap[customerKey].total += duration;
      });

      const customers = Object.values(customerMap).sort((a, b) => a.customerName.localeCompare(b.customerName));
      setCustomerWeekData({ customers, weeks });
      setLoading(false);
    } catch (error) { console.error('Error loading customer week data:', error); setLoading(false); }
  };

  const previousWeek = () => { const d = new Date(currentWeekStart); d.setDate(d.getDate() - 7); setCurrentWeekStart(d); };
  const nextWeek = () => { const d = new Date(currentWeekStart); d.setDate(d.getDate() + 7); setCurrentWeekStart(d); };
  const currentWeek = () => { setCurrentWeekStart(getWeekBounds().start); };

  const downloadCSV = (content, filename) => {
    const blob = new Blob([content], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a'); a.href = url; a.download = filename; a.click(); URL.revokeObjectURL(url);
  };

  const exportSummaryCSV = () => {
    let csv = 'Customer,Project,Task,Mon,Tue,Wed,Thu,Fri,Sat,Sun,Total\n';
    weekData.forEach((customer) => {
      customer.rows.forEach((row) => {
        csv += `"${customer.customerName}","${row.project}","${row.task}",${row.days.map((s) => (s/3600).toFixed(2)).join(',')},${(row.total/3600).toFixed(2)}\n`;
      });
    });
    downloadCSV(csv, `timesheet-summary-${formatDateShort(currentWeekStart)}.csv`);
  };

  const exportDetailedCSV = () => {
    const fmtTime = (iso) => {
      if (!iso) return '';
      const d = new Date(iso);
      return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: false });
    };
    let csv = 'Customer,Project,Task';
    dayNames.forEach((d) => { csv += `,${d}`; });
    csv += ',Total\n';
    detailData.forEach((customer) => {
      customer.rows.forEach((row) => {
        csv += `"${customer.customerName}","${row.project}","${row.task}"`;
        row.days.forEach((entries) => {
          if (entries.length === 0) {
            csv += ',-';
          } else {
            const cellStr = entries.map((e) => `${fmtTime(e.start_time)}-${e.end_time ? fmtTime(e.end_time) : '...'}`).join(' | ');
            csv += `,"${cellStr}"`;
          }
        });
        csv += `,${(row.total/3600).toFixed(2)}\n`;
      });
    });
    downloadCSV(csv, `timesheet-detailed-${formatDateShort(currentWeekStart)}.csv`);
  };

  const exportCustomerWeekCSV = () => {
    if (!customerWeekData) return;
    const { customers, weeks } = customerWeekData;
    const weekLabels = weeks.map((ws) => {
      const we = new Date(ws); we.setDate(we.getDate() + 6);
      return `${formatDateShort(ws)}-${formatDateShort(we)}`;
    });
    let csv = `Customer,${weekLabels.map((l) => `"${l}"`).join(',')},Total\n`;
    customers.forEach((c) => {
      csv += `"${c.customerName}",${c.weeks.map((s) => (s/3600).toFixed(2)).join(',')},${(c.total/3600).toFixed(2)}\n`;
    });
    // Totals row
    const weekTotals = new Array(weeks.length).fill(0);
    let grandTotal = 0;
    customers.forEach((c) => { c.weeks.forEach((s, i) => { weekTotals[i] += s; }); grandTotal += c.total; });
    csv += `"Total",${weekTotals.map((s) => (s/3600).toFixed(2)).join(',')},${(grandTotal/3600).toFixed(2)}\n`;
    downloadCSV(csv, `timesheet-by-customer-week-${formatDateShort(currentWeekStart)}.csv`);
  };

  const handleExport = () => {
    if (viewMode === 'summary') exportSummaryCSV();
    else if (viewMode === 'detailed') exportDetailedCSV();
    else exportCustomerWeekCSV();
  };

  const weekEnd = new Date(currentWeekStart); weekEnd.setDate(weekEnd.getDate() + 6);
  const dayNames = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

  const grandColumnTotals = [0,0,0,0,0,0,0];
  let overallTotal = 0;
  weekData.forEach((customer) => {
    customer.rows.forEach((row) => {
      if (!row.isLunch) {
        row.days.forEach((s, i) => { grandColumnTotals[i] += s; });
        overallTotal += row.total;
      }
    });
  });

  const formatDateTime = (iso) => {
    if (!iso) return '-';
    const d = new Date(iso);
    return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
  };

  return (
    <div className="max-w-7xl mx-auto">
      <div className="bg-white rounded-lg shadow-sm">
        <div className="p-3 border-b border-gray-100">
          <div className="flex items-center justify-between mb-2">
            <h2 className="text-sm font-semibold text-gray-900">Weekly Report</h2>
            <div className="flex items-center gap-2">
              {/* View toggle */}
              <div className="flex items-center bg-gray-100 rounded overflow-hidden">
                <button onClick={() => setViewMode('summary')}
                  className={`px-2 py-1 text-xs flex items-center gap-1 transition-colors ${viewMode === 'summary' ? 'bg-primary-500 text-white' : 'text-gray-600 hover:bg-gray-200'}`}>
                  <BarChart3 className="w-3 h-3" /> Summary
                </button>
                <button onClick={() => setViewMode('detailed')}
                  className={`px-2 py-1 text-xs flex items-center gap-1 transition-colors ${viewMode === 'detailed' ? 'bg-primary-500 text-white' : 'text-gray-600 hover:bg-gray-200'}`}>
                  <List className="w-3 h-3" /> Detailed
                </button>
                <button onClick={() => setViewMode('customer-week')}
                  className={`px-2 py-1 text-xs flex items-center gap-1 transition-colors ${viewMode === 'customer-week' ? 'bg-primary-500 text-white' : 'text-gray-600 hover:bg-gray-200'}`}>
                  <LayoutGrid className="w-3 h-3" /> By Customer
                </button>
              </div>
              {/* CSV download */}
              <button onClick={handleExport}
                className="px-2.5 py-1 text-xs bg-emerald-500 text-white rounded hover:bg-emerald-600 flex items-center gap-1 transition-colors">
                <Download className="w-3 h-3" /><span>CSV</span>
              </button>
            </div>
          </div>

          {viewMode === 'customer-week' ? (
            /* Customer-week controls: weeks selector + end-week navigation */
            <div className="flex items-center justify-center gap-3">
              <button onClick={previousWeek} className="p-1 hover:bg-gray-100 rounded"><ChevronLeft className="w-4 h-4 text-gray-500" /></button>
              <div className="text-center">
                <div className="text-xs font-medium text-gray-900">Ending {formatDateShort(weekEnd)}</div>
                <button onClick={currentWeek} className="text-[10px] text-primary-500 hover:text-primary-600">Current Week</button>
              </div>
              <button onClick={nextWeek} className="p-1 hover:bg-gray-100 rounded"><ChevronRight className="w-4 h-4 text-gray-500" /></button>
              <div className="flex items-center gap-1 ml-2">
                <span className="text-[10px] text-gray-500">Show</span>
                <select value={weeksToShow} onChange={(e) => setWeeksToShow(Number(e.target.value))}
                  className="text-xs border border-gray-200 rounded px-1 py-0.5 text-gray-700 bg-white">
                  <option value={4}>4 weeks</option>
                  <option value={8}>8 weeks</option>
                  <option value={12}>12 weeks</option>
                  <option value={24}>24 weeks</option>
                </select>
              </div>
            </div>
          ) : (
            /* Standard week navigation */
            <div className="flex items-center justify-center gap-3">
              <button onClick={previousWeek} className="p-1 hover:bg-gray-100 rounded"><ChevronLeft className="w-4 h-4 text-gray-500" /></button>
              <div className="text-center min-w-[200px]">
                <div className="text-xs font-medium text-gray-900">{formatDateShort(currentWeekStart)} - {formatDateShort(weekEnd)}</div>
                <button onClick={currentWeek} className="text-[10px] text-primary-500 hover:text-primary-600">Current Week</button>
              </div>
              <button onClick={nextWeek} className="p-1 hover:bg-gray-100 rounded"><ChevronRight className="w-4 h-4 text-gray-500" /></button>
            </div>
          )}
        </div>

        <div className="overflow-x-auto">
          {loading ? (
            <div className="p-4 text-center text-gray-400 text-xs">Loading...</div>
          ) : viewMode === 'customer-week' ? (
            /* ===== CUSTOMER & WEEK VIEW ===== */
            !customerWeekData || customerWeekData.customers.length === 0 ? (
              <div className="p-4 text-center text-gray-400 text-xs">No entries in this period</div>
            ) : (
              <div className="p-4">
                <div className="border border-gray-200 rounded-lg overflow-hidden">
                  <table className="w-full text-xs">
                    <thead className="bg-gray-50 border-b border-gray-100">
                      <tr>
                        <th className="px-3 py-1.5 text-left font-medium text-gray-500 sticky left-0 bg-gray-50">Customer</th>
                        {customerWeekData.weeks.map((ws, i) => {
                          const we = new Date(ws); we.setDate(we.getDate() + 6);
                          return (
                            <th key={i} className="px-2 py-1.5 text-right font-medium text-gray-500 whitespace-nowrap">
                              {formatDateShort(ws)}
                            </th>
                          );
                        })}
                        <th className="px-2 py-1.5 text-right font-medium text-gray-500">Total</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                      {customerWeekData.customers.map((customer, ci) => (
                        <tr key={ci} className="hover:bg-gray-50">
                          <td className="px-3 py-1.5 font-medium text-gray-900 sticky left-0 bg-white">{customer.customerName}</td>
                          {customer.weeks.map((seconds, wi) => (
                            <td key={wi} className="px-2 py-1.5 text-right font-mono text-gray-500">
                              {seconds > 0 ? formatDuration(seconds) : <span className="text-gray-200">-</span>}
                            </td>
                          ))}
                          <td className="px-2 py-1.5 text-right font-mono font-semibold text-gray-900">{formatDuration(customer.total)}</td>
                        </tr>
                      ))}
                      {/* Weekly totals row */}
                      {(() => {
                        const weekTotals = new Array(customerWeekData.weeks.length).fill(0);
                        let grandTotal = 0;
                        customerWeekData.customers.forEach((c) => {
                          c.weeks.forEach((s, i) => { weekTotals[i] += s; });
                          grandTotal += c.total;
                        });
                        return (
                          <tr className="bg-emerald-50 font-bold border-t-2 border-emerald-200">
                            <td className="px-3 py-2 text-gray-900 sticky left-0 bg-emerald-50">Total</td>
                            {weekTotals.map((s, i) => (
                              <td key={i} className="px-2 py-2 text-right font-mono text-gray-900">{s > 0 ? formatDuration(s) : <span className="text-gray-300">-</span>}</td>
                            ))}
                            <td className="px-2 py-2 text-right font-mono text-gray-900">{formatDuration(grandTotal)}</td>
                          </tr>
                        );
                      })()}
                    </tbody>
                  </table>
                </div>
              </div>
            )
          ) : (weekData.length === 0 && detailData.length === 0) ? (
            <div className="p-4 text-center text-gray-400 text-xs">No entries this week</div>
          ) : viewMode === 'summary' ? (
            /* ===== SUMMARY VIEW ===== */
            <div className="space-y-4 p-4">
              {weekData.map((customer, customerIndex) => {
                const customerColumnTotals = [0,0,0,0,0,0,0];
                let customerTotal = 0;
                customer.rows.forEach((row) => {
                  if (!row.isLunch) {
                    row.days.forEach((s, i) => { customerColumnTotals[i] += s; });
                    customerTotal += row.total;
                  }
                });

                return (
                  <div key={customerIndex} className="border border-gray-200 rounded-lg overflow-hidden">
                    <div className="bg-gray-100 px-3 py-2 border-b border-gray-200">
                      <h3 className="text-sm font-semibold text-gray-900">{customer.customerName}</h3>
                    </div>
                    <table className="w-full text-xs">
                      <thead className="bg-gray-50 border-b border-gray-100">
                        <tr>
                          <th className="px-2 py-1.5 text-left font-medium text-gray-500">Project</th>
                          <th className="px-2 py-1.5 text-left font-medium text-gray-500">Task</th>
                          {dayNames.map((day) => <th key={day} className="px-2 py-1.5 text-right font-medium text-gray-500">{day}</th>)}
                          <th className="px-2 py-1.5 text-right font-medium text-gray-500">Total</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {customer.rows.map((row, rowIndex) => (
                          <tr key={rowIndex} className={row.isLunch ? 'bg-amber-50' : 'hover:bg-gray-50'}>
                            <td className="px-2 py-1.5 text-gray-900">{row.project}</td>
                            <td className="px-2 py-1.5 text-gray-900">{row.task}</td>
                            {row.days.map((seconds, di) => <td key={di} className="px-2 py-1.5 text-right font-mono text-gray-500">{seconds > 0 ? formatDuration(seconds) : '-'}</td>)}
                            <td className="px-2 py-1.5 text-right font-mono font-medium text-gray-900">{formatDuration(row.total)}</td>
                          </tr>
                        ))}
                        <tr className="bg-gray-50 font-semibold">
                          <td colSpan="2" className="px-2 py-1.5 text-gray-900">Subtotal (excl. lunch)</td>
                          {customerColumnTotals.map((s, i) => <td key={i} className="px-2 py-1.5 text-right font-mono text-gray-900">{s > 0 ? formatDuration(s) : '-'}</td>)}
                          <td className="px-2 py-1.5 text-right font-mono text-gray-900">{formatDuration(customerTotal)}</td>
                        </tr>
                      </tbody>
                    </table>
                  </div>
                );
              })}

              {/* Grand Total */}
              <div className="border-t-2 border-gray-300 pt-2">
                <div className="bg-emerald-50 border border-emerald-200 rounded-lg overflow-hidden">
                  <table className="w-full text-xs">
                    <tbody>
                      <tr className="font-bold">
                        <td colSpan="2" className="px-3 py-2 text-gray-900">Grand Total (excl. lunch)</td>
                        {grandColumnTotals.map((s, i) => <td key={i} className="px-2 py-2 text-right font-mono text-gray-900">{s > 0 ? formatDuration(s) : '-'}</td>)}
                        <td className="px-2 py-2 text-right font-mono text-gray-900">{formatDuration(overallTotal)}</td>
                      </tr>
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          ) : (
            /* ===== DETAILED VIEW ===== */
            <div className="space-y-4 p-4">
              {detailData.map((customer, ci) => {
                const customerColumnTotals = [0,0,0,0,0,0,0];
                let customerTotal = 0;
                customer.rows.forEach((row) => {
                  if (!row.isLunch) {
                    row.days.forEach((entries, i) => {
                      const daySum = entries.reduce((s, e) => s + e.duration, 0);
                      customerColumnTotals[i] += daySum;
                    });
                    customerTotal += row.total;
                  }
                });

                return (
                  <div key={ci} className="border border-gray-200 rounded-lg overflow-hidden">
                    <div className="bg-gray-100 px-3 py-2 border-b border-gray-200">
                      <h3 className="text-sm font-semibold text-gray-900">{customer.customerName}</h3>
                    </div>
                    <table className="w-full text-xs">
                      <thead className="bg-gray-50 border-b border-gray-100">
                        <tr>
                          <th className="px-2 py-1.5 text-left font-medium text-gray-500">Project</th>
                          <th className="px-2 py-1.5 text-left font-medium text-gray-500">Task</th>
                          {dayNames.map((day) => <th key={day} className="px-1.5 py-1.5 text-center font-medium text-gray-500">{day}</th>)}
                          <th className="px-2 py-1.5 text-right font-medium text-gray-500">Total</th>
                        </tr>
                      </thead>
                      <tbody className="divide-y divide-gray-50">
                        {customer.rows.map((row, ri) => (
                          <tr key={ri} className={row.isLunch ? 'bg-amber-50' : 'hover:bg-gray-50'}>
                            <td className="px-2 py-1.5 text-gray-900 align-top">{row.project}</td>
                            <td className="px-2 py-1.5 text-gray-900 align-top">{row.task}</td>
                            {row.days.map((entries, di) => (
                              <td key={di} className="px-1.5 py-1.5 align-top text-center">
                                {entries.length > 0 ? (
                                  <div className="space-y-0.5">
                                    {entries.map((e, ei) => (
                                      <div key={ei} className="font-mono text-[10px] text-gray-600 whitespace-nowrap">
                                        {formatDateTime(e.start_time)}
                                        <span className="text-gray-300">-</span>
                                        {e.end_time ? formatDateTime(e.end_time) : '...'}
                                      </div>
                                    ))}
                                    <div className="font-mono text-[10px] font-semibold text-gray-800">
                                      {formatDuration(entries.reduce((s, e) => s + e.duration, 0))}
                                    </div>
                                  </div>
                                ) : (
                                  <span className="text-gray-300">-</span>
                                )}
                              </td>
                            ))}
                            <td className="px-2 py-1.5 text-right font-mono font-medium text-gray-900 align-top">{formatDuration(row.total)}</td>
                          </tr>
                        ))}
                        <tr className="bg-gray-50 font-semibold">
                          <td colSpan="2" className="px-2 py-1.5 text-gray-900">Subtotal (excl. lunch)</td>
                          {customerColumnTotals.map((s, i) => <td key={i} className="px-1.5 py-1.5 text-center font-mono text-gray-900">{s > 0 ? formatDuration(s) : '-'}</td>)}
                          <td className="px-2 py-1.5 text-right font-mono text-gray-900">{formatDuration(customerTotal)}</td>
                        </tr>
                      </tbody>
                    </table>
                  </div>
                );
              })}

              {/* Grand Total */}
              <div className="border-t-2 border-gray-300 pt-2">
                <div className="bg-emerald-50 border border-emerald-200 rounded-lg overflow-hidden">
                  <table className="w-full text-xs">
                    <tbody>
                      <tr className="font-bold">
                        <td colSpan="2" className="px-3 py-2 text-gray-900">Grand Total (excl. lunch)</td>
                        {grandColumnTotals.map((s, i) => <td key={i} className="px-1.5 py-2 text-center font-mono text-gray-900">{s > 0 ? formatDuration(s) : '-'}</td>)}
                        <td className="px-2 py-2 text-right font-mono text-gray-900">{formatDuration(overallTotal)}</td>
                      </tr>
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default WeeklyReport;
